sys_script_fix.script:
(function enableNotifications() {
      var log = function(m) { gs.info('[ChainNotif] ' + m); };

      var managerUserNames = ['abraham.lincoln','charles.beckley','george.washington','taylor.vreeland','megan.burke'];
      var processed = 0;

      for (var i = 0; i < managerUserNames.length; i++) {
          if (enableForUser(managerUserNames[i])) processed++;
      }

      var owners = new GlideRecord('sys_user');
      owners.addQuery('x_1880990_chain_u_chain_external_sys_id', '!=', '');
      owners.query();
      while (owners.next()) {   
          if (enableForUser(owners.user_name.toString())) processed++;
      }

      log('=== Total notification=Enable: ' + processed + ' ===');

      function enableForUser(userName) {
          var u = new GlideRecord('sys_user');
          u.addQuery('user_name', userName);
          u.query();  
          if (!u.next()) { gs.error('[ChainNotif] user nao encontrado: ' + userName); return false; }

          u.notification = 2;   
          u.update();
          log('notification enabled: ' + userName);
          return true;
      }
  })();
